// Parse GPT-4 response and extract generated content
const response = $input.item.json;
const content = JSON.parse(response.choices[0].message.content);

const results = [];

for (let i = 0; i < content.length; i++) {
  const post = content[i];
  results.push({
    json: {
      content: post.content,
      hashtags: post.hashtags,
      generatedAt: new Date().toISOString(),
      platform: 'twitter',
      status: 'pending_quality_check',
      version: i + 1
    }
  });
}

return results;

// Parse quality scoring results
const scoringResponse = $input.item.json;
const scores = JSON.parse(scoringResponse.choices[0].message.content);

// Merge with original content
const originalData = $('Parse Generated Content').item.json;

return {
  json: {
    ...originalData,
    qualityScore: scores.total_score,
    engagementScore: scores.engagement_score,
    seoScore: scores.seo_score,
    brandVoiceScore: scores.brand_voice_score,
    readabilityScore: scores.readability_score,
    ctaScore: scores.cta_score,
    feedback: scores.feedback,
    riskLevel: scores.risk_level,
    riskReason: scores.risk_reason || 'None',
    needsImprovement: scores.total_score < 70,
    improvementAttempts: 0
  }
};

// Parse improved content
const improveResponse = $input.item.json;
const improved = JSON.parse(improveResponse.choices[0].message.content);

// Get original data
const originalData = $('Parse Quality Scores').item.json;

return {
  json: {
    content: improved.content,
    hashtags: improved.hashtags,
    generatedAt: new Date().toISOString(),
    platform: originalData.platform,
    status: 'pending_quality_check',
    version: originalData.version,
    improvementAttempts: originalData.improvementAttempts + 1,
    previousScore: originalData.qualityScore,
    previousFeedback: originalData.feedback
  }
};

// Parse sentiment and risk analysis
const analysisResponse = $input.item.json;
const analysis = JSON.parse(analysisResponse.choices[0].message.content);

// Get content data
const contentData = $('Parse Quality Scores').item.json;

return {
  json: {
    ...contentData,
    sentiment: analysis.sentiment,
    riskLevel: analysis.risk_level,
    riskFactors: analysis.risk_factors,
    recommendations: analysis.recommendations,
    culturalAppropriateness: analysis.cultural_appropriateness,
    finalRiskAssessment: analysis.risk_level === 'high' ? 'auto_reject' : (analysis.risk_level === 'medium' || contentData.qualityScore < 70) ? 'requires_approval' : 'auto_approve'
  }
};

// Analyze past posts to create brand voice profile
const posts = $input.all();

if (posts.length === 0) {
  return {
    json: {
      brandVoiceProfile: "デフォルトプロファイル: カジュアルで親しみやすく、ビジネスパーソン向けの有益な情報を提供",
      analyzedPosts: 0
    }
  };
}

const contents = posts.map(p => p.json.Content || p.json.content).filter(c => c);

const analysisData = {
  totalPosts: contents.length,
  averageLength: Math.round(contents.reduce((sum, c) => sum + c.length, 0) / contents.length),
  hashtagUsage: posts.flatMap(p => p.json.Hashtags || p.json.hashtags || []),
  emojiCount: contents.reduce((sum, c) => sum + (c.match(/[\u{1F300}-\u{1F9FF}]/gu) || []).length, 0),
  questionPosts: contents.filter(c => c.includes('?') || c.includes('?')).length
};

return {
  json: {
    brandVoiceAnalysis: analysisData,
    analyzedPosts: contents.length,
    topHashtags: [...new Set(analysisData.hashtagUsage)].slice(0, 10)
  }
};

// Handle approval webhook
const action = $input.item.json.query.action; // approve, reject, edit
const contentId = $input.item.json.query.id;
const editedContent = $input.item.json.body?.editedContent;

return {
  json: {
    action: action,
    contentId: contentId,
    editedContent: editedContent,
    approvedBy: $input.item.json.body?.approvedBy || 'Unknown',
    timestamp: new Date().toISOString()
  }
};
